import xml.etree.ElementTree as ET

def parse_xml(file):
    settings = {}
    tree = ET.parse(file)
    root = tree.getroot()

    for elem in root.iter():
        key = elem.tag
        value = ET.tostring(elem, encoding='unicode', method='text').strip().replace('<', '').replace('>', '')
        settings[key] = value

    return settings